  <div class="en">
  <svg viewBox="0 0 700 400" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
    <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Japanese bond yields vs. the August 2024 yen carry unwind shock</text>
    <g font-family="sans-serif">
      <text x="20" y="60" fill="#a1a1aa" font-size="13">Japanese government bond yields (as of July 2026)</text>
      <text x="40" y="93" fill="#e4e4e7" font-size="14">10-year</text>
